{"filePath":"PodcastEpisodes.swift","content":"import Foundation

struct EpisodeLookupResult: Codable {
  let resultCount: Int
  let results: [EpisodeEntry]
}

struct EpisodeEntry: Codable {
  let wrapperType: String
  let trackName: String?
  let releaseDate: String?
  let description: String?
  let episodeUrl: String?
  let trackTimeMillis: Int?
}

func fetchEpisodes(podcastId: Int, limit: Int = 20) async throws -> [EpisodeEntry] {
  var components = URLComponents(string: "https://itunes.apple.com/lookup")!
  components.queryItems = [
    URLQueryItem(name: "id", value: String(podcastId)),
    URLQueryItem(name: "entity", value: "podcastEpisode"),
    URLQueryItem(name: "limit", value: String(limit)),
  ]
  let (data, _) = try await URLSession.shared.data(from: components.url!)
  let result = try JSONDecoder().decode(EpisodeLookupResult.self, from: data)
  // First result is the podcast itself, rest are episodes
  return result.results.filter { $0.wrapperType == "podcastEpisode" }
}"}
